using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 breaking change: discriminator property renamed to "$type".
            // Preserve EF8 property name for compatibility with existing 500K documents.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 breaking change: id format changed from "EntityName|KeyValue" to just "KeyValue".
            // Preserve EF8 id format so existing documents remain accessible.
            entity.HasKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();

            // EF Core 9 removed HasIndex for Cosmos — indexes are managed in Azure portal/IaC.
            // entity.HasIndex(p => p.Sku); // removed: throws at runtime in EF9
        });
    }
}

